INSERT INTO irac_notes (code, title, description, category)
VALUES
    ('C002', 'Western Area Frequency Coordinator', 'Subject to coordination with the Western Area Frequency Coordinator located at the Naval Air Warfare Center, Weapons Division, China Lake, CA, prior to use within a 322 kilometer radius of Pt. Mugu or in California south of Latitude 37 30'' North.', 'Coordination'),
    ('C003', 'Western Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Western Area Frequency Coordinator (WAFC) who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C004', 'Eastern Area Frequency Coordinator', 'Subject to coordination with the Eastern Area Frequency Coordinator located at Patrick AFB, FL, prior to use within the area bounded by 24°N-31°30''N and 77°W-83°W.', 'Coordination'),
    ('C005', 'Eastern Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Eastern Area Frequency Coordinator, Patrick AFB, FL, who also coordinated it, as appropriate, with Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C006', 'White Sands Area Frequency Coordinator', 'Subject to coordination with the Area Frequency Coordinator located at White Sands Missile Range, NM, prior to use in the State of New Mexico or other U.S. territory within a 240 kilometer radius of WSMR plus the area of Utah and Colorado that lies south of 41°North and between 108°and 111°West; Telephone 505-678-5417 or 3702, DSN: 258-5417 or 3702.', 'Coordination'),
    ('C007', 'White Sands Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Area Frequency Coordinator, WSMR, NM, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C008', 'Arizona Area Frequency Coordinator', 'Subject to coordination with the Area Frequency Coordinator, State of Arizona, Attn: SFIS-FAC-SH, Ft. Huachuca, AZ 85613-5000; Telephone 520-538-6423; FAX 520-538-8525; DSN 879-6423.', 'Coordination'),
    ('C009', 'Arizona Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Area Frequency Coordinator, Ft. Huachuca, AZ, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C010', 'Gulf Area Frequency Coordinator', 'Subject to coordination with the Gulf Area Frequency Coordinator located at Eglin AFB, FL, prior to use within the area bounded by 24°N-33°30''N and 83°W-90°W.', 'Coordination'),
    ('C011', 'Gulf Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Gulf Area Frequency Coordinator, Eglin AFB, FL, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C012', 'Pacific Joint Frequency Management Office', 'Subject to coordination with the Joint Frequency Management Office located at the Commander-in-Chief, Pacific Headquarters, Camp H. M. Smith, HI, prior to use with the area enclosed by 322 kilometer radius of Honolulu, HI.', 'Coordination'),
    ('C013', 'Edwards AFB Frequency Manager', 'Subject to local coordination with Frequency Manager, AFFTC, Edwards AFB, CA.', 'Coordination'),
    ('C015', 'Vandenberg AFB Frequency Manager', 'Subject to prior coordination with Frequency Manager, Air Force Space and Missile Technical Center, Vandenberg AFB, CA.', 'Coordination'),
    ('C016', 'Air Force Spectrum Management Office (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Air Force Spectrum Management Office, Fort Meade, MD, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C019', 'Army Frequency Management Office', 'Subject to prior coordination with Army Frequency Management Office U.S. and Possessions (AFMO US&P), ATTN: CIO G6/SAIS-AOS-A 2350 Stanley Road, Suite 32, Ft. Sam Houston, TX 78234-5032; Telephone 210-221-2050/2820, (DSN 471).', 'Coordination'),
    ('C022', 'Army Missile Command Frequency Manager', 'Subject to prior coordination with Frequency Manager, Army Missile Command, Huntsville, AL.', 'Coordination'),
    ('C024', 'Army Frequency Management Office (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to its authorization with AFMO US&P, Ft. Sam Houston, TX, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C027', 'DOE Area Frequency Coordinator', 'Subject to prior coordination with DOE Area Frequency Coordinator, Las Vegas, NV, when used within the State of Nevada or within a 160 kilometer radius of Mercury or Tonopah, NV; Telephone 575-3458 or 1162 FTS, 702-295-3458 or 1162, Commercial, and 575-3343 FTS or, 702-295-3343 Commercial (weekends, holidays, and off-duty hours).', 'Coordination'),
    ('C030', 'Department of Commerce Frequency Control', 'The Department of Commerce is designated as control for federal use of this frequency. Use under this assignment is subject to initial coordination with, and subsequent coordination as indicated by, Radio Frequency Coordinator S.I.G. Research Facilities Center, NOAA, Department of Commerce, P.O. Box 520197, Miami, FL 33152; Telephone 305-526-2936 (FTS 350-2936).', 'Coordination'),
    ('C031', 'FAA Coordination Required', 'Subject to prior coordination with FAA', 'Coordination'),
    ('C052', 'FCC Engineer-in-Charge Coordination', 'Subject to local coordination with FCC Engineer-in-Charge to avoid interference to non-federal services.', 'Coordination'),
    ('C057', 'NASA Johnson Space Center', 'Subject to prior coordination with NASA Spectrum Manager, Johnson Space Center, Houston, TX; Telephone (FTS) 525-0122 or (commercial) 713-483-0122.', 'Coordination'),
    ('C060', 'Military Installation Commander Coordination (Pre-operational)', 'Prior to operational use, this frequency assignment must be coordinated with and concurred by the commander of the military installation listed.', 'Coordination'),
    ('C061', 'Military Installation Commander Coordination (Completed)', 'Operational use of this frequency assignment has been coordinated with and concurred by the commander of the military installation listed.', 'Coordination'),
    ('C062', 'DOE Telemetering Coordination', 'DOE use of this frequency for telemetering is subject to prior coordination at the national level with agencies having assignments in the same band and will be subject, at the time of such coordination, to adjustment to preclude harmful interference.', 'Coordination'),
    ('C065', 'National Interagency Fire Center', 'Subject to coordination, prior to use, with the Department of the Interior, Bureau of Land Management, National Interagency Fire Center, Boise, ID; Telephone 208-387-5644.', 'Coordination'),
    ('C067', 'Nellis AFB Area Frequency Coordinator', 'Subject to coordination with the Area Frequency Coordinator located at Nellis AFB, NV, prior to use in the states of Nevada, Utah west of 111°W and Idaho south of 44°N.', 'Coordination'),
    ('C068', 'Nellis AFB Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Area Frequency Coordinator, Nellis AFB, NV, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C069', 'NOAA Satellite Operations Facility', 'Subject to coordination and scheduling with Ms. Letecia Reeves, U.S. Department of Commerce; National Oceanic and Atmospheric Administration (NOAA); National Environmental Satellite, Data, and Information Service (NESDIS); Satellite Products and Services Division (SPSD); NOAA Satellite Operations Facility, 4231 Suitland Road, (Room 1646), Suitland, MD 20746, telephone 301-817-4563.', 'Coordination'),
    ('C073', 'NASA Wallops Flight Facility', 'Subject to prior coordination with NASA Spectrum Manager, Wallops Flight Facility, Wallops Island, VA; Telephone 757-824-1623.', 'Coordination'),
    ('C074', 'NASA JPL/Goldstone', 'Operational activities should be coordinated with NASA Spectrum Manager responsible for JPL/Goldstone Programs. Mail: 4800 Oak Grove Drive, Mail Stop 303-404, Pasadena, CA 91109; Telephone (FTS) 8-792-0068 or (commercial) 818-354-0068.', 'Coordination'),
    ('C075', 'Hydrology Coordinator', 'This assignment has been coordinated with the Hydrology Coordinator in accordance with Section 8.3.6.', 'Coordination'),
    ('C076', 'National Science Foundation', 'This assignment has been coordinated with the Electromagnetic Spectrum Manager, National Science Foundation, 4201 Wilson Blvd., Arlington, VA 22230; E-mail: esm@nsf.gov, in accordance with Section 8.3.7, for the band 1660-1670 MHz, or Section 8.3.19 of the NTIA Manual.', 'Coordination'),
    ('C078', 'NTIA Domestic Fixed Coordination', 'The domestic fixed aspects of this assignment have been coordinated with NTIA in accordance with Section 8.2.11 of the NTIA Manual.', 'Coordination'),
    ('C081', 'National Radio Quiet Zone', 'This assignment is for a station in the National Radio Quiet Zone. Successful coordination has been effected in accordance with Section 8.3.9 of the NTIA Manual.', 'Coordination'),
    ('C085', 'Military District of Washington', 'Subject to prior coordination with Army Frequency Coordinator, Military District of Washington, Attn: ASNKO-PB, Fort Lesley J. McNair, Washington, DC 20319-5050; Telephone 202-475-2554 or 2486, DSN 335-2554 or 2486.', 'Coordination'),
    ('C086', 'Mid-Atlantic Area Frequency Coordinator (Flight Test)', 'This frequency assignment in one of the bands 1435-1525, 2310-2320 and 2345-2390 MHz was coordinated prior to authorization with the Mid-Atlantic Area Frequency Coordinator, Patuxent River, MD, who also coordinated it, as appropriate, with the Aerospace and Flight Test Radio Coordinating Council.', 'Coordination'),
    ('C088', 'Aberdeen Proving Ground Frequency Manager', 'Prior to use, this frequency assignment must be scheduled with the Post Frequency Manager, Aberdeen Proving Ground, MD, Telephone 410-278-7591; DSN 298-7591.', 'Coordination'),
    ('C094', 'Naval Air Warfare Center Aircraft Division', 'Subject to coordination with the Area Frequency Coordinator located at the Naval Air Warfare Center Aircraft Division, Patuxent River, MD, prior to use within the area enclosed by 100 kilometer radius of Headquarters Building, Naval Air Warfare Center Aircraft Division, Patuxent River, MD.', 'Coordination'),
    ('C095', 'Primary Use Agreement', 'The non-military agency allotted primary use of this frequency, or which shares primary allotment status with AGA, has agreed neither Record Notes P074 nor P076 are required for this assignment.', 'Coordination'),
    ('E013', 'A3 emission authorized', 'A3 emission authorized for secondary and intermittent operation.', 'Emission'),
    ('E023', 'Voice transmission test only', 'Voice transmission is authorized for test and maintenance only.', 'Emission'),
    ('E028', 'Lower sideband transmission', 'Lower sideband transmission. The carrier is higher than the assigned frequency shown by one half of the indicated bandwidth. (Applies to SSB transmission.)', 'Emission'),
    ('E029', 'Upper sideband transmission', 'Upper sideband transmission. The carrier is lower than the assigned frequency shown by one half of the indicated bandwidth. (Applies to SSB transmission.)', 'Emission'),
    ('E030', 'Lower sideband greater (1.5 kHz)', 'Lower sideband greater. The suppressed carrier is higher than the assigned frequency shown by 1.5 kHz. (Applies to SSB transmission.)', 'Emission'),
    ('E031', 'Upper sideband greater (1.5 kHz)', 'Upper sideband greater. The suppressed carrier is lower than the assigned frequency shown by 1.5 kHz. (Applies to SSB transmission.)', 'Emission'),
    ('E032', 'Lower sideband greater (0.5 kHz)', 'Lower sideband greater. The suppressed carrier is higher than the assigned frequency shown by 0.5 kHz. (Applies to SSB transmission.)', 'Emission'),
    ('E033', 'Upper sideband greater (0.5 kHz)', 'Upper sideband greater. The suppressed carrier is lower than the assigned frequency shown by 0.5 kHz. (Applies to SSB transmission.)', 'Emission'),
    ('E035', 'Lower sideband transmission', 'Lower sideband transmission. (Applies to SSB transmission.)', 'Emission'),
    ('E036', 'Upper sideband transmission', 'Upper sideband transmission. (Applies to SSB transmission.)', 'Emission'),
    ('E037', 'Full-carrier SSB emission', 'Full-carrier SSB emission (3KH3E) shall be used except (1) when it is known that the receiving station is capable of receiving suppressed-carrier emission (3KJ3E) and (2) upon request of any station using the same carrier frequency (Ref: FCC 87.67b).', 'Emission'),
    ('E038', 'Center of intelligence at assigned frequency', 'When a single sideband emission is used from the various single sideband emissions of different bandwidths (Example: 1K20J2A, 2K70R3E, 3K20H3E), the carrier frequency will be set to place the center of intelligence at the assigned frequency.', 'Emission'),
    ('E039', 'Emission bandwidth within authorized band', 'The authorized emission bandwidth shall be so located within the band that it does not extend beyond the upper or lower limits of the authorized band shown in the *FRB entry of circuit remarks. If a portion(s) of the authorized band is to be excluded (*FBE) the authorized emission bandwidth must not extend into any portion(s) of the excluded band(s).', 'Emission'),
    ('L2', 'Time of operation restriction', 'Restricted to (daytime, nighttime, or indicated hours of operation.) Wherever used herein the term daytime means from two hours after local sunrise until two hours before local sunset.', 'Limitation'),
    ('L003', 'Communication with stations only', 'For communication with stations only.', 'Limitation'),
    ('L12', 'Emergency use only', 'To be used only in an emergency jeopardizing life, public safety, or important property under conditions calling for immediate communication where other means of communication do not exist or are temporarily disrupted or inadequate.', 'Limitation'),
    ('L113', 'Emergency use fixed stations', 'L012 FX - Emergency use only for fixed stations.', 'Limitation'),
    ('L116', 'Daytime restrictions', 'Use restricted to daytime hours only (two hours after local sunrise until two hours before local sunset).', 'Limitation'),
    ('L121', 'Daytime Hawaii and westward', 'L2 daytime Hawaii and westward - Restricted to daytime hours in Hawaii and locations westward.', 'Limitation'),
    ('L125', 'Sunrise to sunset restriction', 'L2 local sunrise to local sunset - Restricted to daylight hours from local sunrise to local sunset.', 'Limitation'),
    ('L131', 'Nighttime restrictions', 'L2 nighttime - Restricted to nighttime hours only.', 'Limitation'),
    ('L171', 'Agriculture communications only', 'L3 Agriculture - Limited to communications with Agriculture stations only.', 'Limitation'),
    ('L174', 'Army communications only', 'L3 Army - Limited to communications with Army stations only.', 'Limitation'),
    ('L180', 'Coast Guard communications only', 'L3 Coast Guard - Limited to communications with Coast Guard stations only.', 'Limitation'),
    ('L182', 'Interior Department communications only', 'L3 Interior - Limited to communications with Department of Interior stations only.', 'Limitation'),
    ('L187', 'Military communications only', 'L3 Military - Limited to communications with military stations only.', 'Limitation'),
    ('L188', 'Military aircraft communications only', 'L3 Military aircraft or aircraft authorized for military use - Limited to communications with military aircraft or aircraft authorized for military use.', 'Limitation'),
    ('L190', 'Navy communications only', 'L3 Navy - Limited to communications with Navy stations only.', 'Limitation'),
    ('L192', 'Non-federal communications only', 'L3 non-federal - Limited to communications with non-federal stations only.', 'Limitation'),
    ('L195', 'Non-federal coast stations only', 'L3 non-federal coast stations - Limited to communications with non-federal coast stations only.', 'Limitation'),
    ('L197', 'Non-federal public correspondence only', 'L3 non-federal public correspondence - Limited to communications with non-federal public correspondence stations only.', 'Limitation'),
    ('L199', 'Non-federal ships only', 'L3 non-federal ships - Limited to communications with non-federal ships only.', 'Limitation'),
    ('L201', 'Public correspondence only', 'L3 public correspondence - Limited to public correspondence communications only.', 'Limitation'),
    ('L203', 'U.S. Army Engineers only', 'L3 U.S. Army Engineers - Limited to communications with U.S. Army Engineers stations only.', 'Limitation'),
    ('L282', 'Back-up use only', 'This assignment is for ''back-up'' use only when regular channels are either temporarily disrupted or inadequate.', 'Limitation'),
    ('L283', 'Port and waterway communications', 'Limited to communications in or near a port, or in locks or waterways, between coast stations and ship stations, or between ship stations, in which messages are restricted to those related to the operational handling, the movement and the safety of ships, and, in emergency, to the safety of persons. Messages which are of a public correspondence nature shall be excluded.', 'Limitation'),
    ('L294', 'Time restriction 1400-2200 GMT', 'L2 1400-2200 GMT - Restricted to operations between 1400-2200 GMT.', 'Limitation'),
    ('L308', 'Commerce Department only', 'L3 Commerce - Limited to communications with Department of Commerce stations only.', 'Limitation'),
    ('L309', 'Emergency fixed base only', 'L012 FB - Emergency use only for fixed base stations.', 'Limitation'),
    ('L318', 'Temporary seismic telemetry', 'Authority under this assignment is limited to temporary periods and locations for telemetry of seismic data.', 'Limitation'),
    ('L330', 'Non-federal ship safety communications', 'This assignment is limited to communications with non-federal ships for the exchange of traffic dealing with safety of life or property when other means of communication are not practicable.', 'Limitation'),
    ('L331', 'Time restriction 0900-1300 and 1400-1600 GMT', 'L2 0900-1300 and 1400-1600 GMT - Restricted to operations between 0900-1300 and 1400-1600 GMT.', 'Limitation'),
    ('L332', 'Time restriction 2200-0300 GMT', 'L2 2200-0300 GMT - Restricted to operations between 2200-0300 GMT.', 'Limitation'),
    ('L341', 'Bridge-to-Bridge operations', 'Limited to operations conducted in accordance with Bridge-to-Bridge portion of Section 8.2.29 of the NTIA Manual.', 'Limitation'),
    ('L343', 'Tennessee Valley Authority only', 'L3 Tennessee Valley Authority - Limited to communications with Tennessee Valley Authority stations only.', 'Limitation'),
    ('L347', 'Time restriction 2330-2230 GMT', 'L2 2330-2230 GMT - Restricted to operations between 2330-2230 GMT.', 'Limitation'),
    ('L350', 'Winter season only', 'Limited to use from November 15 to April 1.', 'Limitation'),
    ('L353', 'Time restriction 0100-0600 Local', 'L2 0100-0600 Local - Restricted to operations between 0100-0600 local time.', 'Limitation'),
    ('L355', 'Ground transmissions only', 'Limited to ground transmissions only.', 'Limitation'),
    ('L357', 'Air/ground frequency backup use', 'This band assignment is authorized only for air/ground frequency assignment in the AAG/MAG bands (118-137 MHz and those frequencies utilized by the FAA for air traffic control in the 225-328.6 and 335.4-400 MHz band) and is for ''back-up'' use only when regular channels are either temporarily disrupted or inadequate. Actual frequencies will be listed in Agency Remarks.', 'Limitation'),
    ('L358', 'Night operations only', 'Use restricted to nighttime operations only (two hours before local sunset until two hours after local sunrise).', 'Limitation'),
    ('M001', 'Administrative coordination required', 'A note concerning this assignment is recorded in the minutes of the FAS meeting at which the application was approved. The source of the note is identified in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M002', 'IRAC coordination reference', 'This assignment was coordinated with IRAC or NTIA, and/or is subject to the conditions stated in the letter, the IRAC Document, the FAS Docket, or the FCC Regulation referenced in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M003', 'Coordination prior to activation', 'Subject to coordination prior to activation and, as appropriate, possible scheduling with the activity(ies) or station(s) listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M004', 'Coordination within interference range', 'Subject to coordination prior to activation and, as appropriate, possible scheduling with the activity(ies) listed in the CIRCUIT REMARKS field (*NTS) when used within interference range of such activity(ies) or station(s).', 'Minute'),
    ('M006', 'National Weather Service coordination', 'Subject to coordination prior to activation with the National Weather Service Meteorologist-In-Charge at the location(s) listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M007', 'Notification of activation required', 'Subject to notification of activation to the agency or activity listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M008', 'Immediate adjustment if interference', 'Operations under the authority of this assignment are subject to immediate adjustment, including cessation, if they result in harmful interference to the operations listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M009', 'Non-interference basis operation', 'Operations under the authority of this assignment a) are on a noninterference basis to the operations of the agency listed in the CIRCUIT REMARKS field (*NTS) on the same or adjacent channel and b) no protection can be afforded by that agency.', 'Minute'),
    ('M010', 'Non-renewable assignment', 'This assignment was agreed to on a non-renewable basis by the agency identified in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M011', 'Non-broadcast hours coordination', 'Limited to the non-broadcast hours of and subject to coordination prior to activation with the station(s) listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M013', 'Marine environmental operations', 'Subject to prior coordination with and concurrence by the organization/official listed in the CIRCUIT REMARKS field (*NTS) and to temporary cessation when required for marine environmental operations.', 'Minute'),
    ('M014', 'Aircraft altitude restriction', 'During transmission, aircraft shall not exceed the altitude listed in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M015', 'SPS system review', 'The system using this assignment was reviewed by the SPS in accordance with Chapter 10 and the assignment is being made subject to conditions stated in the IRAC and SPS documents referenced in the CIRCUIT REMARKS field (*NTS).', 'Minute'),
    ('M017', 'Non-federal space station protection', 'This non-federal space station assignment is made with the understanding that protection cannot be guaranteed to reception of the non-federal earth station(s) identified in the CIRCUIT REMARKS field (*NTS) due to the operation of existing transmitting earth stations and/or federal fixed stations.', 'Minute'),
    ('M018', 'Pre-coordinated application', 'When a frequency application has been pre-coordinated between two agencies prior to the application being submitted to the FAS use this CIRCUIT REMARKS field (*NTS) to indicate agency, person, date and limitations/reference. (optional)', 'Minute'),
    ('P032', 'Non-interference basis', 'Operation on a non-interference basis to other authorized users.', 'Priority'),
    ('P074', 'Primary assignment', 'Primary assignment with protection from interference.', 'Priority'),
    ('P076', 'Secondary assignment', 'Secondary assignment without protection from interference.', 'Priority'),
    ('P077', 'Conditional assignment', 'Assignment conditional upon specific operational requirements.', 'Priority'),
    ('S012', 'Special operations support', 'This assignment supports special operations activities.', 'Special'),
    ('S032', 'Emergency and distress communications', 'Common simplex channel for emergency and distress communications only. Available to all stations operating in or with aeronautical services.', 'Special'),
    ('S034', 'Disaster communications', 'This assignment supports disaster communications operations.', 'Special'),
    ('S035', 'Distress, safety and calling', 'This assignment supports distress, safety and calling operations.', 'Special'),
    ('S038', 'FAC operation simultaneous with RLL', 'FAC operation simultaneous with RLL (Radio Landing Light).', 'Special'),
    ('S041', 'Direction finder calibration', 'For calibrating direction finders.', 'Special'),
    ('S043', 'Emergency air sea rescue', 'For emergency use at scene of air sea rescue.', 'Special'),
    ('S047', 'Hydrologic and meteorological data', 'For transmission of hydrologic and meteorological data.', 'Special'),
    ('S048', 'Hydrologic data transmission', 'For transmission of hydrologic data.', 'Special'),
    ('S059', 'Radio direction finding', 'Radio direction finding operations.', 'Special'),
    ('S063', 'Search and rescue communications', 'This assignment supports search and rescue communications.', 'Special'),
    ('S067', 'Bureau of Indian Affairs net control', 'Subject to Department of the Interior, Bureau of Indian Affairs net control.', 'Special'),
    ('S068', 'Subject to immediate shutdown', 'Subject to immediate shutdown as needs of service may dictate.', 'Special'),
    ('S070', 'Subject to FCC cancellation', 'Subject to immediate cancellation upon notice from FCC.', 'Special'),
    ('S085', 'Training and testing operations', 'Training and testing operations.', 'Special'),
    ('S120', 'Intermittent equipment tests', 'Intermittent equipment tests.', 'Special'),
    ('S139', 'International broadcasting protection', 'Transmissions on this frequency will be discontinued upon receipt of notification to the effect that harmful interference is being caused to the international broadcasting service.', 'Special'),
    ('S141', 'Training operations', 'This assignment supports training operations and exercises.', 'Special'),
    ('S142', 'Drone Control', 'This assignment supports drone/UAS control operations.', 'Special'),
    ('S144', 'Non-conforming assignment', 'This assignment is not in complete conformity with the National Table of Frequency Allocations. Those operations that are conducted under the non-conforming portions of this assignment are on a secondary basis to operations conducted under assignments that are in conformity with the National Table of Frequency Allocations.', 'Special'),
    ('S145', 'Subject to military adjustment', 'This frequency is subject to adjustment upon notice from the military.', 'Special'),
    ('S147', 'Nuclear test frequencies', 'These frequencies are used for a very short time only during actual nuclear test or dry runs prior to actual test. Such use of frequencies will be on a secondary basis subject to the avoidance of harmful interference to all operations established in accordance with international allocations applicable to these frequencies and to all other operations regularly authorized within the United States and Possessions on specific frequencies within these bands.', 'Special'),
    ('S148', 'National emergency communications', 'This assignment supports national emergency communications.', 'Special'),
    ('S149', 'Notification requirement for extended use', 'Any use of this assignment that is not at a transient location or that is for a period exceeding 15 days shall be notified to the FAS.', 'Special'),
    ('S150', 'Allotted to another agency', 'This assignment is for a frequency that has been allotted for the primary use of another agency or for all government agencies (AGA); or, the emission bandwidth overlaps a frequency or frequencies allotted for primary use by another agency or all government agencies (AGA). If the frequency is allotted to another agency, the operations on this frequency must be moved to a properly allotted frequency, unless the agency to which the frequency is allotted agrees to the continued use of their allotted frequency.', 'Special'),
    ('S151', 'Narrowband conversion required', 'This assignment must be narrowbanded in accordance with either Section 4.3.7, 4.3.9, or 5.3.5.2 of the NTIA Manual.', 'Special'),
    ('S154', 'Scene of disaster frequency', 'Scene of disaster frequency.', 'Special'),
    ('S155', 'Television signal relay', 'For interception and retransmission of television signals.', 'Special'),
    ('S157', 'Non-federal service', 'Non-federal service.', 'Special'),
    ('S159', 'Short-distance low-power service', 'U.S. Government short-distance low-power service.', 'Special'),
    ('S160', 'Section 7.12 coordination', 'This assignment has been made pursuant to Section 7.12 of the NTIA Manual and has been coordinated in accordance with Section 8.3.3.', 'Special'),
    ('S164', 'Equal basis non-conforming assignment', 'This assignment is not in complete conformity with the National Table of Frequency Allocations. Nevertheless, in the national interest, it is on an equal basis with assignments that are in conformity with the National Table of Frequency Allocations.', 'Special'),
    ('S165', 'Maritime mobile service coordination', 'This assignment has been made pursuant to Section 7.5.2 of the NTIA Manual for communication with non-federal stations in the maritime mobile service.', 'Special'),
    ('S170', 'Tactical SSB operations (2000W)', 'Authorized additionally in tactical and training operations when employing single sideband equipment with 3KH3E, 4KJ7B, 4KJ9W emissions for use with peak envelope powers not to exceed 2000 watts. All necessary emissions under the several modes of operation, including reduced carriers, shall be within kHz of the listed frequency. If harmful interference is caused to authorized operations, the power of this operation will be reduced to the mean power shown for this listing.', 'Special'),
    ('S171', 'Tactical SSB operations (400W)', 'Authorized additionally in tactical and training operations when employing single sideband equipment with 3KH3E, 4KJ7B, 4KJ9W emissions for use with peak envelope powers not to exceed 400 watts. All necessary emissions under the several modes of operation, including reduced carriers, shall be within kHz of the listed frequency. If harmful interference is caused to authorized operations, the power of this operation will be reduced to the mean power shown for this listing.', 'Special'),
    ('S179', 'Emergency power only - 4kW normal', 'Power shown is for emergencies only. Normal power is 4 kW or less.', 'Special'),
    ('S181', 'Public Law 87-795 authorization', 'This assignment was authorized pursuant to Public Law 87-795.', 'Special'),
    ('S185', 'Secondary service (10 transmitters max)', 'Secondary service. Maximum number of transmitters authorized: 10', 'Special'),
    ('S186', 'Intermittent/emergency power - 20kW normal', 'Power shown is for intermittent or emergency use. Normal power is 20 kW.', 'Special'),
    ('S189', 'Tactical and/or training operations', 'Tactical and/or training operations', 'Special'),
    ('S195', 'Safety Communications', 'Safety Communications', 'Special'),
    ('S196', 'Range safety (command destruct)', 'This assignment is for range safety (command destruct/flight termination) in the band 406.1-420 MHz and is authorized in accordance with Section 8.2.54 of the NTIA Manual with an expiration date not to exceed December 31, 2014.', 'Special'),
    ('S199', 'Navy HF coast telegraph coordination', 'Navy operations authorized by assignments bearing this note shall not cause harmful interference to those non-federal operations existing at the time of authorization. The Navy agrees to make such adjustments of its group of high frequency coast telegraph assignments bearing this note as may be necessary to accommodate necessary expansion or adjustment of the non-federal coast telegraph service.', 'Special'),
    ('S200', 'JCS communication circuit', 'JCS communication circuit', 'Special'),
    ('S205', 'Civil defense network', 'Civil defense network', 'Special'),
    ('S206', 'Inadequate facilities authorization', 'This assignment is for an operation for which other telecommunication facilities do not exist, are inadequate, or are impracticable of installation, and for which the use of frequencies above 30 MHz is not practicable. This note applies to FX or AX station classes only.', 'Special'),
    ('S208', 'Domestic haul overseas traffic', 'This assignment is for the domestic haul of overseas traffic in transit or destined for the United States, for an operation where technical and operational requirements dictate such use. The domestic radio haul is a segment of the overall overseas radio system.', 'Special'),
    ('S211', 'Variable power based on conditions', '50 kW mean power used during emergency or unusually poor propagation conditions. 10 kW mean power used during normal conditions. 2.5 kW mean power used during unusually good propagation conditions.', 'Special'),
    ('S219', 'Emergency power - 3kW normal', 'Power shown is for emergency use. Normal power is 3 kW.', 'Special'),
    ('S227', 'Emergency power - 1.5kW normal', 'Power shown is for emergency use. Normal power is 1.5 kW.', 'Special'),
    ('S233', 'Foreign embassy frequency pool', 'This assignment is part of a frequency pool, and, with Department of State approval, it may be used by foreign embassies that are authorized the use of other frequency assignments under Public Law 87-795.', 'Special'),
    ('S242', 'NASA Unified S-band system', 'The NASA Unified S-band system operates in the 2270-2290 MHz portion of the 2200-2290 MHz space telemetering band on a shared basis. This system will be utilized in space missions of extended duration. In certain geographical areas agencies conducting telemetering operations on the shared frequencies in the 2270-2290 MHz band may be requested by NASA to adjust such operations as necessary to support the space mission involved.', 'Special'),
    ('S264', 'Nuclear testing contingency', 'This assignment will not be used except in the event that full-scale atmospheric nuclear testing is resumed, and it is further subject to prior coordination with USINDOPACOM.', 'Special'),
    ('S265', 'Edwards AFB interference avoidance', 'Transmissions shall be directed so as to avoid harmful interference to FAA stations in the Edwards AFB, CA area.', 'Special'),
    ('S267', 'RACES coordination', 'Required for use in emergency areas when required to make initial contact with RACES units. Also for communications with RACES stations on matters requiring coordination.', 'Special'),
    ('S279', 'Laser telecommunications', 'This listing represents a use of a laser(s) for telecommunication purposes and it is entered in the Government Master File (GMF) for information.', 'Special'),
    ('S286', 'Coast Guard accommodation', 'The Coast Guard agrees to make such adjustments in its coast telegraph operations as necessary to provide an accommodation for non-federal coast radiotelegraph operations anticipated by the designation of this frequency in Part 81, FCC Rules.', 'Special'),
    ('S288', 'National Command Authority support', 'This frequency assignment is to support the National Command Authority. Circuits utilizing this frequency will be maintained in operational status at all times.', 'Special'),
    ('S291', 'Aviation advisory service', 'Operations are subject to compliance with FCC Rules and Regulations Part 87, subpart c. Advisory service shall be given to any private aircraft upon request. The use of this frequency shall not be a deterrent to the establishment of a non-federal advisory station in this area. Operations on this frequency shall cease upon the establishment of non-federal facilities or upon notice of harmful interference thereto.', 'Special'),
    ('S292', 'Navigation aids accommodation', 'Not to be a bar to complete operational implementation of common system aids to air navigation.', 'Special'),
    ('S296', 'Other agency assignment accommodation', 'Not to preclude assignment of this frequency to other agencies at specific locations.', 'Special'),
    ('S297', 'Wide-area Multi-user Land Mobile Justice Network', 'This assignment is part of the Wide-area Multi-user Land Mobile Justice Wireless Network certified by NTIA in IRAC Doc. 31594. The provisions of paragraphs 3 through 5 of Section 8.2.48A of the NTIA Manual, except for the provisions of Paragraph 3 of that Section that require each agency to conduct requirements analysis of need and to conduct an analysis of alternatives to operating their own system, are waived for this assignment.', 'Special'),
    ('S298', 'Department of Interior, Fish and Wildlife Service net control', 'Subject to Department of the Interior, U.S. Fish and Wildlife Service net control.', 'Special'),
    ('S299', 'Buried vertical dipole antenna power', 'Power shown is into a buried vertical dipole. ERP is approximately 1 kW.', 'Special'),
    ('S300', 'Federal Wildlife Telemetry program', 'This assignment in the 162 to 174 MHz band supports the Federal Wildlife Telemetry program managed by the Department of the Interior''s U.S. Fish and Wildlife Service. It is authorized on an non-interference basis and will be used for short-term periods at unspecified locations throughout the United States and possessions.', 'Special'),
    ('S301', 'Non-protected secondary basis operation', 'Operations under the authority of this assignment a) are not protected from harmful interference which may be caused by authorized stations operating in accordance with the National Table of Frequency Allocations and b) are subject to immediate adjustment, including cessation, if they result in harmful interference to authorized stations operating in accordance with that table.', 'Special'),
    ('S302', 'No operational equipment development', 'Subject to the understanding that equipment will not be developed for operational use in this band.', 'Special'),
    ('S303', 'No intended operational use within USP', 'Subject to the understanding that there is not intended operational use of this equipment within USP.', 'Special'),
    ('S319', 'Federal non-interference basis 4940-4990 MHz', 'Federal Government use of frequencies in the 4940-4990 MHz band will be on a non-interference basis to any non-federal operations and shall not hinder the implementation of any non-federal operations.', 'Special'),
    ('S321', 'Planning assignment (3 years max)', 'This assignment is for planning purposes not to exceed 3 years (see Section 9.6.5). The Note will be deleted after the assignment has been activated or this assignment will be deleted after specific locations have been notified.', 'Special'),
    ('S322', 'Station notification requirement', 'Stations established under the authority of this assignment shall conform to its technical particulars and shall be notified, as specified in Section 9.1.3 of the NTIA Manual, for inclusion in the list of Frequency Assignment to Federal Radio Stations.', 'Special'),
    ('S323', 'Federal frequency relocation planning', 'This planning assignment supports the relocation of federal frequency assignments in the bands 1695-1710 MHz and 1755-1780 MHz. This action is required for the future accommodation of commercial wireless systems in these bands (see Annex O of the NTIA Manual). Initial planning assignment authorizations are for three years; however, renewals are at two-year increments thereafter. Record the replacement GMF assignment record serial number in the circuit remarks, and add the appropriate system information in the supplementary details. Remove this note from the record upon activation of the assignment.', 'Special'),
    ('S326', 'Pre-1973 committed system', 'This assignment is for use in a system, or research and development looking toward such a system, for which funds had been committed for Stage 4 (Procurement), as defined in Section 10.4.1 of the NTIA Manual, prior to January 1, 1973.', 'Special'),
    ('S327', 'Marine environmental protection operations', 'Marine environmental protection command/control/surveillance operations. Authorized additionally for other maritime mobile operations when not required for marine environmental purposes.', 'Special'),
    ('S328', 'Assignment not planned for renewal', 'This assignment is not planned for renewal. It has been replaced by another assignment.', 'Special'),
    ('S330', 'Equipment nomenclature requirement', 'The equipment nomenclature or appropriate equipment coding is to be provided within six months after activation of the authorized stations.', 'Special'),
    ('S334', 'Bureau of Land Management net control', 'Subject to Department of the Interior, Bureau of Land Management net control.', 'Special'),
    ('S335', 'Telemetry non-interference to aeronautical mobile', 'This telemetry assignment is on a non-interference, non-protected basis as concerns assignments in the aeronautical mobile service.', 'Special'),
    ('S340', 'DOE scientific missions with protected status', 'To be used in support of DOE scientific missions with protected status for short periods of time during actual operations. Such use will require coordination between the DOD and DOE and will be on a scheduled basis.', 'Special'),
    ('S341', 'WSMR frequency conversion exemption', 'Subject to the continued applicability of note P074, this WSMR assignment is exempt from the requirement to be converted to a frequency listed in Section 4.3.7 of the NTIA Manual.', 'Special'),
    ('S344', 'Section 8.2.20 waiver granted', 'This assignment has been granted a waiver and need not comply to the provisions of Section 8.2.20 of the NTIA Manual.', 'Special'),
    ('S345', 'NEST system emergency deployment', 'DOE operations in the band 4400-4940 MHz under this authority will be for emergency deployment of the NEST system. For such use in a given area, DOE will select clear channels based upon current GMF records. If time permits, DOE will coordinate specific frequencies with the appropriate military frequency managers/coordinators in the field. Tests and training will not be conducted under this authority; frequency applications for such operations will be submitted to the FAS/IRAC on a case by case basis.', 'Special'),
    ('S348', 'FCC Part 95 Subpart D compliance', 'Operations are subject to compliance with FCC Rules and Regulations, Part 95, Subpart D. Transmitters may be operated only by employees of the Federal Government only for the purpose of interfacing with Non-federal licensees to coordinate essential and mutual activities. This authority may be revoked by the Federal Communications Commission in its discretion at any time.', 'Special'),
    ('S349', 'DOE receiver protection outside interference range', 'Not to preclude assignment of this frequency outside of normal land mobile interference range (excluding skip and sporadic E reflection etc.) of DOE receive stations.', 'Special'),
    ('S350', 'FAC backup equipment authorization (35W)', 'In the frequency band 30-400 MHz for this FAC operation, power shown is for primary equipment. Back-up equipment has been engineered and installed with output power up to 35 watts. Use of this back-up equipment is authorized during emergencies and/or failure of primary equipment.', 'Special'),
    ('S351', 'Frequency consolidation planning', 'This assignment is planned for implementation or deletion as a consolidation of frequencies being used.', 'Special'),
    ('S354', 'Space project research/development approval', 'This planned assignment is for a Space Project that has been approved in principle by NTIA in the research/development phase. Some operational characteristics have not been determined. This listing does not provide authority to transmit.', 'Special'),
    ('S355', 'Wide-area common-use frequency', 'This assignment is for a wide-area, common-use frequency pursuant to Section 4.2.3 of the NTIA Manual.', 'Special'),
    ('S356', 'Local-area common-use frequency', 'This assignment is for a local-area, common-use frequency pursuant to Section 4.2.4 of the NTIA Manual.', 'Special'),
    ('S357', 'Emergency power - 10kW normal', 'Power shown is for emergencies only. Normal power is 10 kW.', 'Special'),
    ('S358', 'NTIA Exception 1 exemption', 'This assignment is exempt from referral to NTIA by Exception 1 of the domestic fixed policy in Section 8.2.11 of the NTIA Manual.', 'Special'),
    ('S359', 'NTIA Exception 2 exemption', 'This assignment is exempt from referral to NTIA by Exception 2 of the domestic fixed policy in Section 8.2.11 of the NTIA Manual.', 'Special'),
    ('S360', 'NTIA Exception 3 exemption', 'This assignment is exempt from referral to NTIA by Exception 3 of the domestic fixed policy in Section 8.2.11 of the NTIA Manual.', 'Special'),
    ('S361', 'Multiple fixed stations', 'Multiple transmitting and/or receiving stations operating at FIXED locations are involved in this assignment; and, it is not feasible to indicate all specific locations. (The method of operation must be fully explained in supplementary details when S361 is applied to a frequency assignment.)', 'Special'),
    ('S362', 'Transportable fixed stations', 'One or more transportable transmitting and/or receiving stations operating at fixed locations are utilized in this assignment (STC=FX,EX).', 'Special'),
    ('S366', 'Border Zone power restriction', 'All operations will be outside of the U.S./Canada Border Zone, or for assignments for frequencies below 1000 MHz the power used while operating in the Border Zone will not exceed 5 watts.', 'Special'),
    ('S367', 'National Radio Quiet Zone exceptional authorization', 'This frequency assignment has been made on an exceptional basis for operation in the National Radio Quiet Zone on the conditions that use shall be minimized consistent with operational requirements and that any technical modification to this assignment shall be coordinated in accordance with Section 8.3.9 of the NTIA Manual.', 'Special'),
    ('S368', 'Bureau of Reclamation net control', 'Subject to Department of the Interior, Bureau of Reclamation net control.', 'Special'),
    ('S370', 'Transportable earth station interference avoidance', 'Transportable earth station operations in the 7300-7750 MHz and 8025-8400 MHz bands shall be deployed in such a manner as not to cause harmful interference to existing assignments and will adjust to allow additional stations of other radio services in these bands as required.', 'Special'),
    ('S371', 'Chapter 10 and Section 7.14 compliance', 'This assignment is in accordance with Chapter 10 and Section 7.14 of the NTIA Manual.', 'Special'),
    ('S373', 'Heavily used area EMC capability', 'This assignment, in the 2700-2900 MHz band, is for operation in a designated heavily used area or for collocated operation (see Annex D of the NTIA Manual). This equipment has the capability of implementing the additional Electromagnetic Compatibility (EMC) provisions of RSEC Criteria D under Section 5.3 of the NTIA Manual. Implementation of this capability may be necessary at a later date.', 'Special'),
    ('S375', 'GMF recording method development', 'Operations authorized by assignments bearing this note shall be subject to the GMF recording method being developed in accordance with IRAC Doc. 23200/1 (FAS ADM 830029/1).', 'Special'),
    ('S376', 'USDA Forest Service control', 'Operations on this frequency under direct-control of the USDA, Forest Service.', 'Special'),
    ('S378', 'Emergency maritime power authorization', 'In emergency situations a maximum power of 25 watts for ship stations and 10 watts for coast stations is authorized.', 'Special'),
    ('S379', 'Operation Alliance expiration', 'This assignment shall expire upon conclusion of the Operation Alliance mission.', 'Special'),
    ('S381', 'SHARES traffic support', 'Operations under this assignment are for SHARES traffic in accordance with Section 7.3.8 of the NTIA Manual.', 'Special'),
    ('S382', 'Spectrum management record only', 'This record is retained for spectrum management and analysis purposes and does not constitute an NTIA authority to transmit.', 'Special'),
    ('S383', 'Sounder assignment compliance', 'This sounder assignment complies with Section 8.2.21 of the NTIA Manual. The frequency bands listed in paragraph 1.c. of Section 8.2.21 have been suppressed. The information required by paragraph 2 of Section 8.2.21 is provided in the supplementary details of this assignment.', 'Special'),
    ('S384', 'Part 4.3.2 authorization', 'This assignment has been made pursuant to Part 4.3.2 of the NTIA Manual.', 'Special'),
    ('S385', 'Passive sensor/radio astronomy record', 'This GMF listing identifies passive sensor or radio astronomy receiving stations for spectrum management and analysis purposes and does not constitute an NTIA authority to transmit. Interference protection to the receiving station is afforded only to the extent provided in the National Table of Frequency Allocations.', 'Special'),
    ('S387', 'Narrowband implementation vacation', 'Upon implementation of narrowband operations this channel will be vacated.', 'Special'),
    ('S388', 'DSCS Operations Center earth stations', 'This assignment supports DSCS Operations Center earth stations limited to locations at Fort Detrick, and Fort Meade, MD, and Camp Roberts, CA. This assignment shall not preclude new terrestrial assignments within or overlapping the frequency band 7250-7750 MHz provided each new terrestrial assignment does not exceed a maximum tolerable interfering power of -141.3 dBm in any 30 kHz bandwidth at the earth station receiver. In addition, this assignment has no priority over either future meteorological-satellite systems (See G104) or terrestrial assignments authorized prior to April 26, 1994.', 'Special'),
    ('S390', 'Maritime Mobile Service wideband authorization', 'This assignment for wideband telegraphy, facsimile and/or special transmission systems in the Maritime Mobile Service is being made in accordance with Section 8.2.29, paragraph 5.c.(1) of the NTIA Manual and ITU RR 52.170.', 'Special'),
    ('S391', 'Existing system expansion', 'This assignment is an expansion or enhancement of an existing system in the 138-150.8 or 406.1-420 MHz band which utilizes a bandwidth greater than 11 kHz.', 'Special'),
    ('S396', 'Section 4.3.7 or 4.3.9 compliance', 'This assignment is in accordance with either Section 4.3.7, paragraph 5.d, or Section 4.3.9, paragraph 6.d of the NTIA Manual.', 'Special'),
    ('S397', 'Joint law enforcement requirement', 'This assignment is for a joint law enforcement requirement pursuant to Section 4.3.16 of this Manual.', 'Special'),
    ('S398', 'Joint incident response requirement', 'This assignment is for a joint incident response requirement pursuant to Section 4.3.16 of this Manual.', 'Special'),
    ('S399', '12.5 kHz channel plan non-conformance', 'Effective January 1, 2005, any federal operation in the band 162-174 MHz, not conforming to the 12.5 kHz channel plan, is on a non-interference basis to all operations that do conform to the 12.5 kHz channel plan in accordance with Section 4.3.7 of the NTIA Manual.', 'Special'),
    ('S401', 'Ten-year review requirement', 'This record requires review every 10 years per NTIA Manual, Annex F.', 'Special'),
    ('S402', 'Shared federal/non-federal radio system', 'This assignment has been made pursuant to Section 8.2.47 of the NTIA Manual for a shared federal/non-federal radio system.', 'Special'),
    ('S403', 'Temporary expedited review assignment', 'This is a temporary GMF assignment for a short-term/limited period requirement that the agency request expedited review by the FAS representatives.', 'Special'),
    ('S404', 'NOAA Weather Radio Link requirement', 'This assignment fulfills a requirement for NOAA Weather Radio Link UHF one-way single frequency operation.', 'Special'),
    ('S405', 'UAS FAA authorization requirement', 'Prior to operation under the authority of this assignment for uncrewed aerial system (UAS) a certificate of waiver or authorization must be obtained from the Federal Aviation Administration per 8.3.33.', 'Special'),
    ('S406', 'GPS re-radiator compliance', 'GPS re-radiators must operate in accordance NTIA Manual Chapter 8.3.28. Any malfunction, misalignment or tampering of equipment or its location which results in an increased power spectrial density outside the building could cause harmful radio frequency interference to GPS Receivers, including those in aircraft and/or ground based facilities.', 'Special'),
    ('S545', 'NASA LANDSAT support', 'This assignment supports the NASA/Commerce Earth Exploration Service Space Program LANDSAT.', 'Special'),
    ('S566', 'Advanced Technology Satellite GPS expiration', 'This assignment shall expire upon completion of the Advanced Technology Satellite Global Positioning System space project.', 'Special'),
    ('S567', 'Deep Space Program expiration', 'This assignment shall expire upon completion of the Deep Space Program space project.', 'Special'),
    ('S570', 'FLEETSATCOM expiration', 'This assignment shall expire upon completion of FLEETSATCOM space project.', 'Special'),
    ('S572', 'Air Force Satellite Data System expiration', 'This assignment shall expire upon completion of the Air Force Satellite Data System space project.', 'Special'),
    ('S575', 'NASA TDRSS support', 'This assignment supports the NASA TDRSS space program.', 'Special'),
    ('S576', 'NASA Space Shuttle support', 'This assignment supports the NASA Space SHUTTLE (STS) program.', 'Special'),
