    ('S643', 'DSCS Phase III expiration', 'This assignment shall expire upon completion of Space Project DSCS Phase III.', 'Special'),
    ('S651', 'NASA Space Station support', 'This assignment supports the NASA Space Station space program.', 'Special'),
    ('S662', 'Non-federal Domestic Satellite System', 'This assignment is for Common Carrier service provided in a non-federal Domestic Satellite System. The specific frequency and satellite is dependent upon the Common Carrier selected to provide the service.', 'Special'),
    ('S664', 'STATSIONAR Satellite System expiration', 'This assignment shall expire upon termination of the STATSIONAR Satellite System (USSR).', 'Special'),
    ('S665', 'INMARSAT space system', 'This assignment is in the INMARSAT space system. If this assignment is for a transportable land-based or aeronautical INMARSAT terminal, it is subject to coordination with the Common Carrier Bureau of the Federal Communications Commission. This coordination will be conducted by the Communications Satellite Corporation in accordance with Annex E.', 'Special'),
    ('S666', 'NATO IV space project', 'This assignment supports the NATO IV space project.', 'Special'),
