    ('S737', 'Hughes Communications Galaxy, Inc. GALAXY VIII (I) satellite', 'This assignment supports the Hughes Communications Galaxy, Inc. GALAXY VIII (I) satellite.', 'Special'),
    ('S742', 'Federal earth station supporting foreign space operation (unprotected)', 'This assignment is for use by a Federal Government earth station supporting a foreign space operation. The responsible federal agency has waived the NTIA spectrum certification process for the earth station operation. Therefore, although this operation may be in accordance with the National Table of Frequency Allocations, it must be conducted on an unprotected, non-interference basis to those U.S. operations that are in conformity with the National Table of Frequency Allocations.', 'Special'),
    ('S743', 'EXPRESS Satellite System (Russia) expiration', 'This assignment shall expire upon termination of the EXPRESS Satellite System (Russia).', 'Special'),
    ('S745', 'Federal government space program', 'This assignment supports a federal government space program.', 'Special'),
